import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                key = (name, fw['framework'], pkg['id'])
                result[key] = (pkg['requestedVersion'], pkg['resolvedVersion'])
    return result

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    proj, fw, pkg = key
    bv = b.get(key)
    av = a.get(key)
    if bv and av:
        if bv[1] != av[1]:
            changes.append((proj, fw, pkg, bv[1], av[1], 'Aligned to highest version'))
        else:
            unchanged.append((proj, fw, pkg, av[1]))
    elif bv and not av:
        changes.append((proj, fw, pkg, bv[1], '-', 'Removed'))
    elif av and not bv:
        changes.append((proj, fw, pkg, '-', av[1], 'Added'))

print('=== CHANGES ===')
for c in changes:
    print(f'{c[0]} ({c[1]}) | {c[2]} | {c[3]} -> {c[4]} | {c[5]}')
if not changes:
    print('(none)')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'{u[0]} ({u[1]}) | {u[2]} | {u[3]}')
"

